import React from "react";

const ContenedorLateral = ({
  subtitulo,
  imagen,
  ancho = "clamp(280px, 35vw, 400px)",
  alto = "clamp(320px, 45vh, 480px)",
  ovaloRedondez = "9999px",
  cuadroRedondez = "20px",
  className = ""
}) => {
  return (
    <div
      className={`relative flex flex-col items-center justify-start bg-white border border-[#072D42]/20 shadow-xl transition-all duration-300 hover:shadow-2xl hover:border-[#072D42]/30 ${className}`}
      style={{
        width: ancho,
        height: alto,
        borderRadius: `${cuadroRedondez} 0 0 ${cuadroRedondez}`,
        marginTop: "clamp(2rem, 6vh, 4rem)",
      }}
    >
      {/* Contenedor principal */}
      <div className="relative w-full h-full flex flex-col items-center justify-start p-6">
        
        {/* Óvalo del subtítulo - Diseño profesional */}
        <div
          className="absolute bg-white border border-[#072D42]/20 px-6 py-3 flex items-center justify-center shadow-lg"
          style={{
            borderRadius: ovaloRedondez,
            left: "50%",
            top: "-20px",
            transform: "translateX(-50%)",
            minWidth: "200px",
            maxWidth: "90%",
            height: "50px",
            zIndex: 10,
          }}
        >
          <span className="font-sans font-semibold text-[#072D42] text-sm md:text-base uppercase tracking-wide text-center truncate">
            {subtitulo}
          </span>
        </div>

        {/* Contenedor de la imagen con marco profesional */}
        <div
          className="w-full h-full flex items-center justify-center mt-8"
        >
          <div
            className="relative w-full h-full bg-[#F4E9D7]/30 border-2 border-[#072D42]/10 rounded-xl overflow-hidden group"
            style={{
              borderRadius: ovaloRedondez,
              padding: "clamp(0.5rem, 1.5vw, 1rem)",
            }}
          >
            {/* Marco interior decorativo */}
            <div className="absolute inset-2 border border-[#F29E38]/20 rounded-lg pointer-events-none" />
            
            {/* Imagen con efecto profesional */}
            <div className="w-full h-full relative overflow-hidden rounded-lg">
              <img
                src={imagen}
                alt="Contenido visual"
                className="object-cover w-full h-full transition-all duration-500 group-hover:scale-105"
                style={{
                  borderRadius: "12px",
                }}
                onError={(e) => {
                  e.target.src = "data:image/svg+xml;base64,";
                }}
              />
              
              {/* Overlay sutil al hover */}
              <div className="absolute inset-0 bg-[#072D42]/0 group-hover:bg-[#072D42]/5 transition-all duration-300" />
            </div>

            {/* Efecto de esquina decorativa */}
            <div className="absolute top-2 right-2 w-3 h-3 border-t-2 border-r-2 border-[#F29E38] opacity-60" />
            <div className="absolute bottom-2 left-2 w-3 h-3 border-b-2 border-l-2 border-[#F29E38] opacity-60" />
          </div>
        </div>

        {/* Línea decorativa inferior */}
        <div className="absolute bottom-4 left-1/2 transform -translateX(-50%) w-20 h-1 bg-[#F29E38] rounded-full" />
      </div>

      {/* Borde lateral acentuado */}
      <div className="absolute right-0 top-0 h-full w-1 bg-gradient-to-b from-[#F29E38] to-[#072D42] opacity-80" />
    </div>
  );
};

export default ContenedorLateral;
